#include <bits/stdc++.h>
using namespace std;
const int maxn=505,kd[][2]= {1,0,0,1,0,-1,-1,0};
int n,m,a[maxn][maxn],ans;
void dfs(int i,int j) {
	if(i>1+n&&j>1+m) {
		return;
	}
	a[i][j]=2;
	for(int k=0; k<4; k++) {
		int ii=i+kd[k][0],jj=j+kd[k][1];
		if(ii<=n&&ii>=0&&jj<=m&&jj>=0&&a[ii][jj]==1) {
			dfs(ii,jj);
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=m; j++) {
			char c;
			cin>>c;
			if(c=='*') {
				a[i][j]=0;
			} else {
				a[i][j]=1;
			}
		}
	}
	for(int i=1; i<=n; i++) {
		if(a[i][1]==1) {
			dfs(i,1);
		}
	}
	for(int i=1; i<=n; i++) {
		if(a[i][m]==1) {
			dfs(i,m);
		}
	}
	for(int i=1; i<=m; i++) {
		if(a[n][i]==1) {
			dfs(n,i);
		}
	}
	for(int i=1; i<=m; i++) {
		if(a[1][i]==1) {
			dfs(1,i);
		}
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=m; j++) {
			if(a[i][j]==1) {
				ans++;
			}
		}
	}
	cout<<ans;
	return 0;
}
